export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { GoogleGenAI, Modality } from "@google/genai";
import { decodeBase64, decodeAudioData } from "./audio";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getDailyAffirmation(): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Generate a super girly, empowering, and poetic daily affirmation for a woman's wellness app. Keep it short and beautiful.",
      config: {
        systemInstruction: "You are a supportive and elegant wellness coach.",
      }
    });
    return response.text || "You are blooming exactly as you should.";
  } catch (error) {
    console.error("Affirmation Error:", error);
    return "You are a masterpiece in progress.";
  }
}

export async function playWelcomeVoice(name: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say in a warm, elegant, and welcoming female voice: Hello beautiful ${name}. Welcome back to your sanctuary. I hope you're feeling wonderful today.` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(
        decodeBase64(base64Audio),
        audioContext,
        24000,
        1
      );
      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) {
    console.error("Welcome Voice Error:", error);
  }
}

export async function getGiftIdeas(phase: string): Promise<string[]> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `My partner is in her ${phase} phase of her menstrual cycle. Suggest 5 thoughtful, romantic, or comforting gift ideas for this specific time.`,
      config: {
        systemInstruction: "You are a thoughtful romantic advisor.",
      }
    });
    // Return split lines as a rough array
    return (response.text?.split('\n').filter(s => s.trim().length > 5).slice(0, 5)) || [];
  } catch (error) {
    return ["A bouquet of flowers", "Soft silk pajamas", "A handwritten letter", "Luxury chocolates", "A relaxing foot rub"];
  }
}

import React, { useState, useEffect, useCallback } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import { playWelcomeVoice } from './services/gemini';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea', completed: false },
    { id: '2', task: 'Read for 15 mins', completed: false },
    { id: '3', task: 'Skincare routine', completed: false },
  ]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    playWelcomeVoice(userData.name);
    // Start background music logic could go here too
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab('dashboard');
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} />;
      case 'period':
        return <PeriodTracker user={user} symptoms={symptoms} setSymptoms={setSymptoms} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      case 'yoga':
        return <YogaTutorials />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} />;
      case 'water':
        return <WaterTracker waterIntake={waterIntake} setWaterIntake={setWaterIntake} />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} />;
    }
  };

  return (
    <div className="min-h-screen pb-24 bg-[#fffafb] selection:bg-pink-200">
      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white shadow-sm">
        <div>
          <h1 className="text-3xl font-serif text-pink-500 italic">Lumina</h1>
          <p className="text-xs text-pink-300 tracking-widest uppercase">Bloom & Balance</p>
        </div>
        <button 
          onClick={handleLogout}
          className="text-xs text-gray-400 hover:text-pink-400 transition-colors"
        >
          Logout
        </button>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-6">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-pink-100 flex justify-around items-center py-4 px-2 shadow-lg z-50">
          <NavItem icon="🏠" label="Home" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon="🌸" label="Cycle" active={activeTab === 'period'} onClick={() => setActiveTab('period')} />
          <NavItem icon="🧘‍♀️" label="Zen" active={activeTab === 'yoga'} onClick={() => setActiveTab('yoga')} />
          <NavItem icon="📔" label="Diary" active={activeTab === 'diary'} onClick={() => setActiveTab('diary')} />
          <NavItem icon="✨" label="Self" active={activeTab === 'selfcare'} onClick={() => setActiveTab('selfcare')} />
        </nav>
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-all ${active ? 'text-pink-500 scale-110' : 'text-gray-400'}`}
  >
    <span className="text-xl">{icon}</span>
    <span className="text-[10px] font-bold uppercase tracking-tighter">{label}</span>
  </button>
);

export default App;

