import React from 'react';
import { User, Symptom } from '../types';
import { SYMPTOMS } from '../constants';

interface PeriodTrackerProps {
  user: User;
  symptoms: Symptom[];
  setSymptoms: React.Dispatch<React.SetStateAction<Symptom[]>>;
}

const PeriodTracker: React.FC<PeriodTrackerProps> = ({ symptoms, setSymptoms }) => {
  const toggleSymptom = (type: Symptom['type']) => {
    const existing = symptoms.find(s => s.type === type && s.date === new Date().toDateString());
    if (existing) {
      setSymptoms(symptoms.filter(s => s !== existing));
    } else {
      setSymptoms([...symptoms, {
        id: Math.random().toString(),
        date: new Date().toDateString(),
        type,
        intensity: 2
      }]);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center">
        <h2 className="text-3xl font-serif text-pink-500 italic">Cycle Sanctuary</h2>
        <p className="text-sm text-pink-300 italic">Log your body's whispers</p>
      </header>

      {/* Calendar Preview Placeholder */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
        <div className="grid grid-cols-7 gap-2 text-center text-[10px] font-bold text-pink-300 uppercase mb-4">
          <span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span>
        </div>
        <div className="grid grid-cols-7 gap-4">
          {[...Array(31)].map((_, i) => (
            <div 
              key={i} 
              className={`aspect-square flex items-center justify-center rounded-xl text-sm transition-all cursor-pointer ${i >= 12 && i <= 16 ? 'bg-pink-200 text-white font-bold' : 'hover:bg-pink-50 text-gray-400'}`}
            >
              {i + 1}
            </div>
          ))}
        </div>
        <div className="mt-8 flex justify-center gap-6">
           <div className="flex items-center gap-2 text-[10px] text-pink-300 uppercase font-bold">
              <div className="w-3 h-3 bg-pink-200 rounded-full"></div>
              Prediction
           </div>
           <div className="flex items-center gap-2 text-[10px] text-pink-300 uppercase font-bold">
              <div className="w-3 h-3 bg-pink-400 rounded-full"></div>
              Logged
           </div>
        </div>
      </div>

      <section>
        <h3 className="text-xl font-serif text-pink-500 mb-4 px-2">How are you feeling?</h3>
        <div className="grid grid-cols-3 gap-4">
          {SYMPTOMS.map((s) => {
             const isActive = symptoms.some(item => item.type === s.id && item.date === new Date().toDateString());
             return (
               <button 
                 key={s.id}
                 onClick={() => toggleSymptom(s.id as any)}
                 className={`flex flex-col items-center gap-2 p-6 rounded-[2rem] transition-all border-2 ${isActive ? 'bg-pink-100 border-pink-300 shadow-md' : 'bg-white border-pink-50 hover:border-pink-100'}`}
