import React, { useState, useEffect, useRef } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import { playWelcomeVoice } from './services/gemini';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [volume, setVolume] = useState(0.3);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea', completed: false },
    { id: '2', task: 'Read for 15 mins', completed: false },
    { id: '3', task: 'Skincare routine', completed: false },
  ]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    playWelcomeVoice(userData.name);
    // Auto-play music on login
    setIsMusicPlaying(true);
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab('dashboard');
    setIsMusicPlaying(false);
  };

  const toggleMusic = () => {
    setIsMusicPlaying(!isMusicPlaying);
  };

  useEffect(() => {
    if (isMusicPlaying) {
      audioRef.current?.play().catch(e => console.log("Autoplay blocked or failed", e));
    } else {
      audioRef.current?.pause();
    }
  }, [isMusicPlaying]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} />;
      case 'period':
        return <PeriodTracker user={user} symptoms={symptoms} setSymptoms={setSymptoms} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      case 'yoga':
        return <YogaTutorials />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} />;
      case 'water':
        return <WaterTracker waterIntake={waterIntake} setWaterIntake={setWaterIntake} />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} />;
    }
  };

  return (
    <div className="min-h-screen pb-24 bg-[#fffafb] selection:bg-pink-200">
      <audio 
        ref={audioRef}
        src="https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" 
        loop 
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white shadow-sm sticky top-0 z-[60]">
        <div>
          <h1 className="text-3xl font-serif text-pink-500 italic">Lumina</h1>
          <p className="text-xs text-pink-300 tracking-widest uppercase">Bloom & Balance</p>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 bg-pink-50 px-4 py-2 rounded-full border border-pink-100 shadow-inner">
            <button 
              onClick={toggleMusic}
              className="text-pink-400 hover:text-pink-600 transition-all transform hover:scale-110 active:scale-95"
              title={isMusicPlaying ? "Pause Melodies" : "Play Melodies"}
            >
              {isMusicPlaying ? '⏸️' : '▶️'}
            </button>
            <input 
              type="range" 
              min="0" 
              max="1" 
              step="0.01" 
              value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-16 h-1 bg-pink-200 rounded-lg appearance-none cursor-pointer accent-pink-400"
            />
          </div>

          <button 
            onClick={handleLogout}
            className="text-xs font-bold text-gray-400 hover:text-pink-400 transition-colors uppercase tracking-widest"
          >
            Logout
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-6">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-pink-100 flex justify-around items-center py-4 px-2 shadow-lg z-50">
