import React from 'react';
import { User, Symptom } from '../types';
import { SYMPTOMS } from '../constants';

interface PeriodTrackerProps {
  user: User;
  symptoms: Symptom[];
  setSymptoms: React.Dispatch<React.SetStateAction<Symptom[]>>;
}

const PeriodTracker: React.FC<PeriodTrackerProps> = ({ user, symptoms, setSymptoms }) => {
  const toggleSymptom = (type: Symptom['type']) => {
    const existing = symptoms.find(s => s.type === type && s.date === new Date().toDateString());
    if (existing) {
      setSymptoms(symptoms.filter(s => s !== existing));
    } else {
      setSymptoms([...symptoms, {
        id: Math.random().toString(),
        date: new Date().toDateString(),
        type,
        intensity: 2
      }]);
    }
  };

  // Basic cycle math for the calendar preview
  // Day 1: Period Start
  // Day 1-5: Period
  // Day 10-15: Fertile Window
  // Day 14: Ovulation
  const getDayStatus = (day: number) => {
    const pStart = 1;
    const pEnd = user.periodLength || 5;
    const ovulationDay = (user.cycleLength || 28) - 14;
    const fertileStart = ovulationDay - 4;
    const fertileEnd = ovulationDay + 1;

    if (day >= pStart && day <= pEnd) return 'period';
    if (day === ovulationDay) return 'ovulation';
    if (day >= fertileStart && day <= fertileEnd) return 'fertile';
    return 'none';
  };

  const dayStyles = {
    period: 'bg-pink-400 text-white font-bold shadow-md shadow-pink-100',
    ovulation: 'bg-teal-400 text-white font-bold shadow-md shadow-teal-100 ring-2 ring-teal-200',
    fertile: 'bg-teal-50 text-teal-600 font-medium border border-teal-100',
    none: 'hover:bg-pink-50 text-gray-400'
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center">
        <h2 className="text-3xl font-serif text-pink-500 italic">Cycle Sanctuary</h2>
        <p className="text-sm text-pink-300 italic">Your body, your rhythm, your power</p>
      </header>

