           <div className="flex gap-2">
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">←</button>
              <button className="w-8 h-8 rounded-full bg-pink-50 text-pink-400 flex items-center justify-center hover:bg-pink-100 transition-colors">→</button>
           </div>
        </div>

        <div className="grid grid-cols-7 gap-2 text-center text-[10px] font-bold text-pink-300 uppercase mb-4">
          <span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span>
        </div>

        <div className="grid grid-cols-7 gap-3">
          {/* Offset for start of month - simplified for UI demo */}
          {[...Array(2)].map((_, i) => <div key={`empty-${i}`} />)}

          {[...Array(31)].map((_, i) => {
            const dayNum = i + 1;
            const status = getDayStatus(dayNum);

            return (
              <div 
                key={i} 
                className={`relative aspect-square flex items-center justify-center rounded-2xl text-sm transition-all cursor-pointer ${dayStyles[status]}`}
              >
                {dayNum}
                {status === 'ovulation' && (
                  <span className="absolute -top-1 -right-1 text-[10px]">✨</span>
                )}
              </div>
            );
          })}
        </div>

        {/* Dynamic Legend */}
        <div className="mt-10 grid grid-cols-2 gap-4">
           <div className="flex items-center gap-3 p-3 bg-pink-50/50 rounded-2xl">
              <div className="w-4 h-4 bg-pink-400 rounded-lg shadow-sm"></div>
              <div className="flex flex-col">
                <span className="text-[10px] text-pink-500 uppercase font-black leading-none">Period</span>
                <span className="text-[9px] text-pink-300 italic">Heavy flow expected</span>
              </div>
           </div>
           <div className="flex items-center gap-3 p-3 bg-teal-50/50 rounded-2xl">
              <div className="w-4 h-4 bg-teal-400 rounded-lg shadow-sm"></div>
              <div className="flex flex-col">
                <span className="text-[10px] text-teal-600 uppercase font-black leading-none">Ovulation</span>
