              <div className="w-4 h-4 bg-teal-100 rounded-lg"></div>
              <div className="flex flex-col">
                <span className="text-[10px] text-teal-500 uppercase font-black leading-none">Fertile Window</span>
                <span className="text-[9px] text-teal-300 italic">High chance of conception</span>
