import React, { useState, useEffect, useRef } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask, AppTheme } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import Education from './components/Education';
import PregnancyTracker from './components/PregnancyTracker';
import { playWelcomeVoice } from './services/gemini';
import { THEMES } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [waterGoal, setWaterGoal] = useState(8);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [volume, setVolume] = useState(0.3);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea', completed: false },
    { id: '2', task: 'Read for 15 mins', completed: false },
    { id: '3', task: 'Skincare routine', completed: false },
  ]);

  const handleLogin = (userData: User) => {
    // Inject defaults if missing
    const fullUser = {
      ...userData,
      theme: userData.theme || 'rose',
      isPregnancyMode: userData.isPregnancyMode || false,
      diaryPin: userData.diaryPin || '1234'
    };
    setUser(fullUser);
    playWelcomeVoice(fullUser.name);
    setIsMusicPlaying(true);
  };

  const updateTheme = (newTheme: AppTheme) => {
    if (user) {
      setUser({ ...user, theme: newTheme });
    }
  };

  const togglePregnancy = () => {
    if (user) {
      setUser({ 
        ...user, 
        isPregnancyMode: !user.isPregnancyMode,
        pregnancyStartDate: !user.isPregnancyMode ? new Date().toISOString() : undefined 
      });
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab('dashboard');
    setIsMusicPlaying(false);
  };

  const toggleMusic = () => {
    setIsMusicPlaying(!isMusicPlaying);
  };

  useEffect(() => {
    if (isMusicPlaying) {
      audioRef.current?.play().catch(e => console.log("Autoplay blocked", e));
    } else {
      audioRef.current?.pause();
    }
  }, [isMusicPlaying]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const currentThemeData = THEMES[user.theme || 'rose'];
  const themeClass = `text-${currentThemeData.primary}`;

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} />;
      case 'cycle':
        return user.isPregnancyMode 
          ? <PregnancyTracker user={user} /> 
          : <PeriodTracker user={user} symptoms={symptoms} setSymptoms={setSymptoms} />;
      case 'edu':
        return <Education />;
      case 'yoga':
        return <YogaTutorials />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} user={user} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} />;
    }
  };

  return (
    <div className={`min-h-screen pb-24 ${currentThemeData.bg} selection:bg-pink-100 transition-colors duration-500`}>
      <audio 
        ref={audioRef}
        src="https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" 
        loop 
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-[60]">
        <div>
          <h1 className={`text-3xl font-serif italic ${themeClass}`}>Lumina</h1>
          <div className="flex gap-1 mt-1">
            {(Object.keys(THEMES) as AppTheme[]).map(t => (
              <button 
                key={t}
                onClick={() => updateTheme(t)}
                className={`w-3 h-3 rounded-full border border-white shadow-sm ${t === 'rose' ? 'bg-pink-400' : t === 'lavender' ? 'bg-purple-400' : t === 'mint' ? 'bg-teal-400' : 'bg-orange-400'} ${user.theme === t ? 'ring-2 ring-offset-2 ring-gray-300' : ''}`}
              />
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={togglePregnancy}
            className={`text-[10px] font-bold px-3 py-1 rounded-full border transition-all ${user.isPregnancyMode ? 'bg-indigo-500 text-white border-indigo-500' : 'bg-white text-gray-400 border-gray-200'}`}
          >
            {user.isPregnancyMode ? 'PREGNANCY ON' : 'PREGNANCY OFF'}
          </button>

          <div className="flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-full border border-gray-100">
            <button onClick={toggleMusic} className="text-sm">
              {isMusicPlaying ? '⏸️' : '▶️'}
            </button>
            <input 
              type="range" min="0" max="1" step="0.01" value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-12 h-1 accent-pink-400"
            />
          </div>

          <button onClick={handleLogout} className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Logout
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-6">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-gray-100 flex justify-around items-center py-4 px-2 shadow-[0_-10px_30px_rgba(0,0,0,0.03)] z-50">
          <NavItem icon="🏠" label="Home" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} theme={user.theme} />
          <NavItem icon={user.isPregnancyMode ? "👶" : "🌸"} label={user.isPregnancyMode ? "Baby" : "Cycle"} active={activeTab === 'cycle'} onClick={() => setActiveTab('cycle')} theme={user.theme} />
          <NavItem icon="📖" label="Learn" active={activeTab === 'edu'} onClick={() => setActiveTab('edu')} theme={user.theme} />
          <NavItem icon="📔" label="Diary" active={activeTab === 'diary'} onClick={() => setActiveTab('diary')} theme={user.theme} />
          <NavItem icon="✨" label="Self" active={activeTab === 'selfcare'} onClick={() => setActiveTab('selfcare')} theme={user.theme} />
        </nav>
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void, theme: AppTheme }> = ({ icon, label, active, onClick, theme }) => {
  const color = THEMES[theme].primary;
  return (
    <button 
      onClick={onClick}
      className={`flex flex-col items-center gap-1 transition-all ${active ? `text-${color} scale-110 font-bold` : 'text-gray-400'}`}
    >
      <span className="text-xl">{icon}</span>
      <span className="text-[9px] uppercase tracking-tighter">{label}</span>
    </button>
  );
};

export default App;

import React, { useState } from 'react';
import { DiaryEntry, User } from '../types';

interface DiaryProps {
  entries: DiaryEntry[];
  setEntries: React.Dispatch<React.SetStateAction<DiaryEntry[]>>;
  user: User;
}

const Diary: React.FC<DiaryProps> = ({ entries, setEntries, user }) => {
  const [content, setContent] = useState('');
  const [mood, setMood] = useState('Happy');
  const [isLocked, setIsLocked] = useState(true);
  const [pinInput, setPinInput] = useState('');
  const [error, setError] = useState('');

  const handleUnlock = () => {
    if (pinInput === (user.diaryPin || '1234')) {
      setIsLocked(false);
      setError('');
    } else {
      setError('Incorrect PIN, beautiful. Try again.');
      setPinInput('');
    }
  };

  const addEntry = () => {
    if (!content.trim()) return;
    const newEntry: DiaryEntry = {
      id: Math.random().toString(),
      date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
      content,
      mood
    };
    setEntries([newEntry, ...entries]);
    setContent('');
  };

  if (isLocked) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center p-8 bg-white rounded-[3rem] shadow-sm border border-pink-50 animate-fadeIn">
        <div className="w-20 h-20 bg-pink-50 text-pink-400 rounded-full flex items-center justify-center text-4xl mb-6 shadow-inner">🔒</div>
        <h2 className="text-2xl font-serif text-pink-600 mb-2 italic">Secret Sanctuary</h2>
        <p className="text-sm text-pink-300 mb-8 text-center italic">Your thoughts are safe here. Enter your secret PIN.</p>

        <div className="flex gap-4 mb-6">
          {[...Array(4)].map((_, i) => (
            <div key={i} className={`w-4 h-4 rounded-full border-2 border-pink-200 ${pinInput.length > i ? 'bg-pink-400 border-pink-400' : 'bg-transparent'}`}></div>
          ))}
        </div>

        {error && <p className="text-rose-400 text-xs mb-4 font-bold uppercase">{error}</p>}

        <div className="grid grid-cols-3 gap-4">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9, 'C', 0, '✓'].map((num) => (
            <button 
              key={num}
              onClick={() => {
                if (num === 'C') setPinInput('');
                else if (num === '✓') handleUnlock();
                else if (pinInput.length < 4) setPinInput(prev => prev + num);
              }}
              className="w-16 h-16 rounded-2xl bg-pink-50/50 hover:bg-pink-100 text-pink-600 font-bold text-xl transition-all active:scale-95"
            >
              {num}
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center relative">
        <h2 className="text-3xl font-serif text-pink-500 italic">Whispers of the Soul</h2>
        <p className="text-sm text-pink-300 italic">Your private, blooming thoughts</p>
        <button 
          onClick={() => setIsLocked(true)}
          className="absolute top-0 right-0 p-2 bg-gray-50 text-gray-400 rounded-full hover:bg-gray-100 transition-colors text-[10px] font-bold uppercase"
        >
          Lock Diary
        </button>
      </header>

      <section className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50 space-y-4">
        <div className="flex gap-4 mb-4 overflow-x-auto pb-2 scrollbar-hide">
           {['Happy', 'Calm', 'Moody', 'Sad', 'Tired', 'Blessed', 'Inspired'].map(m => (
             <button 
               key={m} 
               onClick={() => setMood(m)}
               className={`px-4 py-2 rounded-full text-[10px] font-bold uppercase whitespace-nowrap transition-all ${mood === m ? 'bg-pink-400 text-white shadow-md' : 'bg-pink-50 text-pink-300'}`}
             >
               {m}
             </button>
           ))}
        </div>
        <textarea 
          value={content}
          onChange={(e) => setContent(e.target.value)}
          placeholder="What's on your heart today, lovely?"
          className="w-full h-40 bg-pink-50/30 p-6 rounded-3xl outline-none focus:ring-2 focus:ring-pink-100 text-gray-700 font-serif italic text-lg resize-none"
        />
        <button 
          onClick={addEntry}
          className="w-full py-4 bg-pink-400 text-white rounded-2xl font-bold uppercase tracking-widest shadow-lg shadow-pink-100 hover:bg-pink-500 transition-all"
        >
          Save Entry
        </button>
      </section>

      <div className="space-y-6">
        {entries.map((entry) => (
          <div key={entry.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50 border-l-4 border-l-pink-300 group hover:border-l-pink-500 transition-all">
            <div className="flex justify-between items-center mb-4">
              <p className="text-[10px] font-bold text-pink-300 uppercase">{entry.date}</p>
              <span className="text-[10px] px-3 py-1 bg-pink-50 text-pink-400 rounded-full font-bold uppercase">{entry.mood}</span>
            </div>
            <p className="text-gray-600 font-serif italic text-lg leading-relaxed whitespace-pre-wrap">"{entry.content}"</p>
          </div>
        ))}
      </div>
    </div>
  );
};

