import React from 'react';
import { User } from '../types';
import { BABY_SIZES } from '../constants';

interface PregnancyTrackerProps {
  user: User;
}

const PregnancyTracker: React.FC<PregnancyTrackerProps> = ({ user }) => {
  const startDate = user.pregnancyStartDate ? new Date(user.pregnancyStartDate) : new Date();
  const diffTime = Math.abs(new Date().getTime() - startDate.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  const weeks = Math.min(40, Math.floor(diffDays / 7) + 1); // Mock progression starting from Week 1

  const currentBaby = BABY_SIZES.find(b => b.week === Math.floor(weeks / 4) * 4) || BABY_SIZES[0];

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center">
        <h2 className="text-3xl font-serif text-indigo-500 italic">New Life Journey</h2>
        <p className="text-sm text-indigo-300 italic">Growing something beautiful every day</p>
      </header>

      <section className="bg-white p-10 rounded-[3rem] shadow-sm border border-indigo-50 flex flex-col items-center">
        <div className="w-48 h-48 bg-indigo-50 rounded-full flex items-center justify-center text-8xl mb-6 shadow-inner animate-pulse">
           {currentBaby.fruit}
        </div>
        <h3 className="text-4xl font-serif text-indigo-600 mb-2 italic">Week {weeks}</h3>
        <p className="text-sm text-indigo-300 uppercase font-bold tracking-widest mb-6">Baby is as big as a {currentBaby.size}</p>

        <div className="w-full h-3 bg-indigo-50 rounded-full overflow-hidden">
          <div className="h-full bg-indigo-400" style={{ width: `${(weeks / 40) * 100}%` }}></div>
        </div>
        <p className="text-[10px] text-indigo-300 mt-2 font-bold uppercase tracking-widest">{40 - weeks} weeks to go!</p>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
