import React, { useState, useEffect } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [mode, setMode] = useState<'user' | 'partner'>('user');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Simulated local storage database
  const getStoredUsers = (): any[] => {
    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Simulate API delay
    setTimeout(() => {
      const users = getStoredUsers();

      if (isLogin) {
        // Login Logic
        const foundUser = users.find(u => u.email === email && u.password === password);
        if (foundUser) {
          onLogin(foundUser);
        } else {
          setError('Invalid email or password. Please try again, darling.');
          setLoading(false);
        }
      } else {
        // Sign Up Logic
        if (users.some(u => u.email === email)) {
          setError('An account with this email already exists.');
          setLoading(false);
          return;
        }

        // Fix: Added missing isPregnancyMode and theme to satisfy User interface requirements
        const newUser: User & { password: string } = {
          id: Math.random().toString(36).substr(2, 9),
          name: name || 'Beautiful',
          email,
          password,
          partnerName: mode === 'user' ? 'Lover' : 'My Bloom',
          cycleLength: 28,
          periodLength: 5,
          lastPeriodStart: new Date().toISOString(),
          isPartner: mode === 'partner',
          isPregnancyMode: false,
          theme: 'rose',
          diaryPin: '1234'
        };

        users.push(newUser);
        localStorage.setItem('lumina_users', JSON.stringify(users));
        onLogin(newUser);
      }
    }, 1200);
  };

  return (
    <div className="min-h-screen bg-[#fffafb] flex items-center justify-center p-4 relative overflow-hidden">
      {/* Decorative Background Elements */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-pink-100 rounded-full blur-[100px] opacity-50"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-rose-100 rounded-full blur-[120px] opacity-50"></div>
      <div className="absolute top-1/4 right-10 w-20 h-20 text-pink-200 opacity-20 rotate-12 text-6xl">🌸</div>
      <div className="absolute bottom-1/4 left-10 w-20 h-20 text-rose-200 opacity-20 -rotate-12 text-6xl">✨</div>

      <div className="bg-white/70 backdrop-blur-2xl p-8 md:p-12 rounded-[3rem] shadow-[0_20px_50px_rgba(249,168,212,0.2)] w-full max-w-lg z-10 border border-white/50 flex flex-col items-center">
        <div className="mb-8 text-center">
          <h1 className="text-5xl font-serif text-pink-500 mb-2 italic tracking-tighter">Lumina</h1>
          <p className="text-pink-300 uppercase tracking-[0.3em] text-[10px] font-bold">Secure Sanctuary</p>
        </div>

        {/* Auth Mode Toggle */}
        <div className="flex bg-pink-50/50 p-1.5 rounded-2xl mb-8 w-full border border-pink-100/50">
          <button 
            onClick={() => setIsLogin(true)}
            className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all duration-300 ${isLogin ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
          >
            SIGN IN
          </button>
          <button 
            onClick={() => setIsLogin(false)}
            className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all duration-300 ${!isLogin ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
          >
            JOIN US
          </button>
        </div>

        {/* Identity Toggle (Only on Sign Up) */}
        {!isLogin && (
          <div className="flex bg-rose-50/30 p-1 rounded-full mb-8 w-full border border-rose-100/50">
            <button 
              onClick={() => setMode('user')}
              className={`flex-1 py-2 rounded-full text-[10px] font-bold transition-all ${mode === 'user' ? 'bg-pink-400 text-white shadow-md' : 'text-pink-300'}`}
            >
              I AM BLOOMING
            </button>
            <button 
              onClick={() => setMode('partner')}
              className={`flex-1 py-2 rounded-full text-[10px] font-bold transition-all ${mode === 'partner' ? 'bg-pink-400 text-white shadow-md' : 'text-pink-300'}`}
            >
              I AM SUPPORTING
            </button>
          </div>
        )}

        <form onSubmit={handleSubmit} className="w-full space-y-5">
          {error && (
            <div className="bg-rose-50 text-rose-500 text-[11px] font-bold p-4 rounded-2xl border border-rose-100 text-center animate-shake">
              {error}
            </div>
          )}

          {!isLogin && (
            <div className="group">
              <label className="block text-[10px] font-bold text-pink-300 uppercase mb-2 ml-4">Full Name</label>
              <div className="relative">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-pink-300">🎀</span>
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-12 pr-6 py-4 bg-white border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 placeholder:text-pink-200 transition-all shadow-sm"
                  placeholder="Your lovely name..."
                  required={!isLogin}
                />
              </div>
            </div>
          )}

          <div className="group">
            <label className="block text-[10px] font-bold text-pink-300 uppercase mb-2 ml-4">Email Address</label>
            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-pink-300">✉️</span>
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-12 pr-6 py-4 bg-white border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 placeholder:text-pink-200 transition-all shadow-sm"
                placeholder="hello@beautiful.com"
                required
              />
            </div>
          </div>

          <div className="group">
            <label className="block text-[10px] font-bold text-pink-300 uppercase mb-2 ml-4">Password</label>
            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-pink-300">🔒</span>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-12 pr-6 py-4 bg-white border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 placeholder:text-pink-200 transition-all shadow-sm"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className="w-full py-5 bg-gradient-to-r from-pink-400 to-rose-400 hover:from-pink-500 hover:to-rose-500 text-white rounded-2xl font-bold shadow-xl shadow-pink-200 transition-all transform hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:translate-y-0 flex items-center justify-center gap-3"
          >
            {loading ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
            ) : (
              <>
                {isLogin ? 'WELCOME BACK' : 'START YOUR JOURNEY'}
                <span className="text-xl">✨</span>
              </>
            )}
          </button>
        </form>

        <div className="mt-10 flex flex-col items-center gap-4">
          <div className="flex items-center gap-2 text-[10px] text-pink-300 uppercase font-bold tracking-widest">
            <span className="w-10 h-[1px] bg-pink-100"></span>
            Privacy First
            <span className="w-10 h-[1px] bg-pink-100"></span>
          </div>
          <p className="text-[10px] text-gray-400 text-center max-w-[250px] leading-relaxed">
            Your data is locally protected and encrypted. We believe your cycle and thoughts are your sacred business.
          </p>
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-5px); }
          75% { transform: translateX(5px); }
        }
        .animate-shake {
          animation: shake 0.3s ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default Auth;

export type AppTheme = 'rose' | 'lavender' | 'mint' | 'peach';

export interface User {
  id: string;
  name: string;
  email: string;
  partnerName: string;
  cycleLength: number;
  periodLength: number;
  lastPeriodStart: string;
  isPartner: boolean;
  // New properties
  isPregnancyMode: boolean;
  pregnancyStartDate?: string;
  diaryPin?: string;
  theme: AppTheme;
}

export interface Symptom {
  id: string;
  date: string;
  type: 'cramps' | 'headache' | 'bloating' | 'moody' | 'acne' | 'fatigue';
  intensity: 1 | 2 | 3;
}

export interface DiaryEntry {
  id: string;
  date: string;
  content: string;
  mood: string;
}

export interface SelfCareTask {
  id: string;
  task: string;
  completed: boolean;
}

export interface Song {
  title: string;
  artist: string;
  url: string;
  tags: string[];
}

export interface Reminder {
  id: string;
  text: string;
  time: string;
  isCompleted: boolean;
}

import React, { useState, useEffect, useRef } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask, AppTheme, Reminder } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import Education from './components/Education';
import PregnancyTracker from './components/PregnancyTracker';
import { playWelcomeVoice } from './services/gemini';
import { THEMES } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [waterGoal, setWaterGoal] = useState(8);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [volume, setVolume] = useState(0.3);
  const [reminders, setReminders] = useState<Reminder[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea', completed: false },
    { id: '2', task: 'Read for 15 mins', completed: false },
    { id: '3', task: 'Skincare routine', completed: false },
  ]);

  const handleLogin = (userData: User) => {
    const fullUser = {
      ...userData,
      theme: userData.theme || 'rose',
      isPregnancyMode: userData.isPregnancyMode || false,
      diaryPin: userData.diaryPin || '1234'
    };
    setUser(fullUser);
    playWelcomeVoice(fullUser.name);
    setIsMusicPlaying(true);
  };

  const updateTheme = (newTheme: AppTheme) => {
    if (user) {
      setUser({ ...user, theme: newTheme });
    }
  };

  const togglePregnancy = () => {
    if (user) {
      setUser({ 
        ...user, 
        isPregnancyMode: !user.isPregnancyMode,
        pregnancyStartDate: !user.isPregnancyMode ? new Date().toISOString() : undefined 
      });
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab('dashboard');
    setIsMusicPlaying(false);
  };

  const toggleMusic = () => {
    setIsMusicPlaying(!isMusicPlaying);
  };

  useEffect(() => {
    if (isMusicPlaying) {
      audioRef.current?.play().catch(e => console.log("Autoplay blocked", e));
    } else {
      audioRef.current?.pause();
    }
  }, [isMusicPlaying]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const currentThemeData = THEMES[user.theme || 'rose'];
  const themeClass = `text-${currentThemeData.primary}`;

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} reminders={reminders} setReminders={setReminders} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} reminders={reminders} />;
      case 'cycle':
        return user.isPregnancyMode 
          ? <PregnancyTracker user={user} /> 
          : <PeriodTracker user={user} symptoms={symptoms} setSymptoms={setSymptoms} />;
      case 'edu':
        return <Education />;
      case 'yoga':
        return <YogaTutorials />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} user={user} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} reminders={reminders} />;
    }
  };

  return (
    <div className={`min-h-screen pb-24 ${currentThemeData.bg} selection:bg-pink-100 transition-colors duration-500`}>
      <audio 
        ref={audioRef}
        src="https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" 
        loop 
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-[60]">
        <div>
          <h1 className={`text-3xl font-serif italic ${themeClass}`}>Lumina</h1>
          <div className="flex gap-1 mt-1">
            {(Object.keys(THEMES) as AppTheme[]).map(t => (
              <button 
                key={t}
                onClick={() => updateTheme(t)}
                className={`w-3 h-3 rounded-full border border-white shadow-sm ${t === 'rose' ? 'bg-pink-400' : t === 'lavender' ? 'bg-purple-400' : t === 'mint' ? 'bg-teal-400' : 'bg-orange-400'} ${user.theme === t ? 'ring-2 ring-offset-2 ring-gray-300' : ''}`}
              />
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          {!user.isPartner && (
            <button 
              onClick={togglePregnancy}
              className={`text-[10px] font-bold px-3 py-1 rounded-full border transition-all ${user.isPregnancyMode ? 'bg-indigo-500 text-white border-indigo-500' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              {user.isPregnancyMode ? 'PREGNANCY ON' : 'PREGNANCY OFF'}
            </button>
          )}

          <div className="flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-full border border-gray-100">
            <button onClick={toggleMusic} className="text-sm">
              {isMusicPlaying ? '⏸️' : '▶️'}
            </button>
            <input 
              type="range" min="0" max="1" step="0.01" value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-12 h-1 accent-pink-400"
            />
          </div>

          <button onClick={handleLogout} className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Logout
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-6">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-gray-100 flex justify-around items-center py-4 px-2 shadow-[0_-10px_30px_rgba(0,0,0,0.03)] z-50">
          <NavItem icon="🏠" label="Home" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} theme={user.theme} />
          <NavItem icon={user.isPregnancyMode ? "👶" : "🌸"} label={user.isPregnancyMode ? "Baby" : "Cycle"} active={activeTab === 'cycle'} onClick={() => setActiveTab('cycle')} theme={user.theme} />
          <NavItem icon="📖" label="Learn" active={activeTab === 'edu'} onClick={() => setActiveTab('edu')} theme={user.theme} />
          <NavItem icon="📔" label="Diary" active={activeTab === 'diary'} onClick={() => setActiveTab('diary')} theme={user.theme} />
          <NavItem icon="✨" label="Self" active={activeTab === 'selfcare'} onClick={() => setActiveTab('selfcare')} theme={user.theme} />
        </nav>
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void, theme: AppTheme }> = ({ icon, label, active, onClick, theme }) => {
  const color = THEMES[theme].primary;
  return (
    <button 
      onClick={onClick}
      className={`flex flex-col items-center gap-1 transition-all ${active ? `text-${color} scale-110 font-bold` : 'text-gray-400'}`}
    >
      <span className="text-xl">{icon}</span>
      <span className="text-[9px] uppercase tracking-tighter">{label}</span>
    </button>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { User, Reminder } from '../types';
import { getGiftIdeas } from '../services/gemini';

interface PartnerModeProps {
  user: User;
  reminders: Reminder[];
  setReminders: React.Dispatch<React.SetStateAction<Reminder[]>>;
}

const PartnerMode: React.FC<PartnerModeProps> = ({ user, reminders, setReminders }) => {
  const [giftIdeas, setGiftIdeas] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [newReminderText, setNewReminderText] = useState('');
  const [newReminderTime, setNewReminderTime] = useState('');

  useEffect(() => {
    setLoading(true);
    getGiftIdeas("Luteal").then(ideas => {
      setGiftIdeas(ideas);
      setLoading(false);
    });
  }, []);

  const addReminder = () => {
    if (!newReminderText.trim()) return;
    const reminder: Reminder = {
      id: Math.random().toString(36).substr(2, 9),
      text: newReminderText,
      time: newReminderTime || 'Today',
      isCompleted: false
    };
    setReminders([...reminders, reminder]);
    setNewReminderText('');
    setNewReminderTime('');
  };

  const toggleReminder = (id: string) => {
    setReminders(reminders.map(r => r.id === id ? { ...r, isCompleted: !r.isCompleted } : r));
  };

  const deleteReminder = (id: string) => {
    setReminders(reminders.filter(r => r.id !== id));
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <header className="relative bg-gradient-to-br from-indigo-50 to-pink-50 p-10 rounded-[2.5rem] shadow-inner text-indigo-900 overflow-hidden">
