        <p className="text-sm opacity-60 mb-8 italic">Your guide to being the best partner today.</p>

        <div className="bg-white/60 backdrop-blur-md p-6 rounded-2xl border border-white/40">
           <p className="text-xs font-bold uppercase tracking-widest text-indigo-400 mb-2">Cycle Status</p>
           <div className="flex items-center justify-between">
              <div>
                 <p className="text-2xl font-serif text-pink-600 italic">Day 23: Luteal Phase</p>
                 <p className="text-xs text-indigo-400 mt-1 uppercase font-bold">They might feel more tired or sensitive right now.</p>
              </div>
              <div className="text-3xl animate-bounce">💌</div>
           </div>
        </div>
        <div className="absolute -bottom-10 -left-10 text-9xl text-pink-100 opacity-50 rotate-12">🌸</div>
      </header>

      {/* Support Reminders Section */}
      <section className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
        <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2">
           <span className="text-2xl">⏰</span> Support Reminders
        </h3>

        <div className="space-y-4 mb-8">
          <div className="flex flex-col md:flex-row gap-3">
            <input 
              type="text" 
              value={newReminderText}
              onChange={(e) => setNewReminderText(e.target.value)}
              placeholder="e.g., Drink water at 2 PM"
              className="flex-1 px-5 py-3 rounded-2xl bg-pink-50/30 border border-pink-50 focus:ring-2 focus:ring-pink-200 outline-none text-sm text-pink-700 italic"
            />
            <input 
              type="text" 
              value={newReminderTime}
              onChange={(e) => setNewReminderTime(e.target.value)}
              placeholder="Time/Day"
              className="md:w-32 px-5 py-3 rounded-2xl bg-pink-50/30 border border-pink-50 focus:ring-2 focus:ring-pink-200 outline-none text-sm text-pink-700 italic"
            />
            <button 
              onClick={addReminder}
              className="px-6 py-3 bg-indigo-400 text-white rounded-2xl font-bold uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-md active:scale-95"
            >
              Set Reminder
            </button>
          </div>
        </div>

        <div className="space-y-3">
          {reminders.length === 0 ? (
            <p className="text-center py-6 text-gray-400 italic text-sm">No reminders set yet. Help them stay blooming!</p>
          ) : (
            reminders.map((reminder) => (
              <div 
                key={reminder.id} 
                className={`flex items-center justify-between p-5 rounded-2xl transition-all border ${reminder.isCompleted ? 'bg-gray-50 border-transparent opacity-60' : 'bg-white border-indigo-50 hover:border-indigo-200 shadow-sm'}`}
              >
                <div className="flex items-center gap-4">
                  <button 
                    onClick={() => toggleReminder(reminder.id)}
                    className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${reminder.isCompleted ? 'bg-indigo-400 border-indigo-400' : 'border-indigo-200'}`}
                  >
                    {reminder.isCompleted && <span className="text-white text-[10px]">✓</span>}
                  </button>
                  <div>
                    <p className={`font-serif italic text-lg ${reminder.isCompleted ? 'line-through text-gray-400' : 'text-indigo-900'}`}>{reminder.text}</p>
                    <p className="text-[10px] text-indigo-300 font-bold uppercase">{reminder.time}</p>
                  </div>
                </div>
                <button 
                  onClick={() => deleteReminder(reminder.id)}
                  className="text-gray-300 hover:text-rose-400 transition-colors"
                >
                  <span className="text-xl">×</span>
                </button>
              </div>
            ))
          )}
        </div>
      </section>

      <section className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
        <h3 className="text-xl font-serif text-pink-500 mb-6 flex items-center gap-2">
           <span className="text-2xl">🎁</span> Gift & Support Ideas
        </h3>

        {loading ? (
          <div className="flex flex-col items-center gap-4 py-10">
             <div className="w-10 h-10 border-4 border-pink-100 border-t-pink-400 rounded-full animate-spin"></div>
             <p className="text-xs text-pink-300 uppercase font-bold tracking-widest">Generating thoughtful ideas...</p>
          </div>
        ) : (
          <div className="grid gap-4">
            {giftIdeas.map((idea, i) => (
              <div key={i} className="group p-5 bg-pink-50/50 rounded-2xl hover:bg-pink-50 transition-all border border-transparent hover:border-pink-100">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm">
                     {['💝', '💐', '☕', '🕯️', '🍪'][i % 5]}
                  </div>
                  <p className="text-gray-700 font-serif italic text-lg leading-tight">{idea}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-pink-50">
         <h3 className="text-xl font-serif text-pink-500 mb-4">Pro-Tip for Today</h3>
         <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100 italic text-indigo-700 text-sm leading-relaxed">
            "During the Luteal phase, hormone shifts can cause irritability or anxiety. The best gift you can give right now is extra patience and active listening. Maybe handle the dinner cleanup without being asked? It goes a long way! 🌸"
         </div>
      </section>
    </div>
  );
};

