import React, { useState } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [mode, setMode] = useState<'user' | 'partner'>('user');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Simulated local storage database
  const getStoredUsers = (): any[] => {
    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const cleanEmail = email.trim().toLowerCase();
    const cleanPassword = password.trim();

    if (!cleanEmail || !cleanPassword) {
      setError('Please fill in all fields, darling.');
      return;
    }

    setLoading(true);

    // Simulate API delay
    setTimeout(() => {
      const users = getStoredUsers();

      if (isLogin) {
        // Login Logic with normalized inputs
        const foundUser = users.find(u => 
          u.email.trim().toLowerCase() === cleanEmail && 
          u.password.trim() === cleanPassword
        );

        if (foundUser) {
          onLogin(foundUser);
        } else {
          setError('Incorrect email or password. Please try again, beautiful.');
          setLoading(false);
        }
      } else {
        // Sign Up Logic
        if (users.some(u => u.email.trim().toLowerCase() === cleanEmail)) {
          setError('An account with this email already exists.');
          setLoading(false);
          return;
        }

        const newUser: User & { password: string } = {
          id: Math.random().toString(36).substr(2, 9),
          name: (name.trim() || 'Beautiful'),
          email: cleanEmail,
          password: cleanPassword,
          partnerName: mode === 'user' ? 'Lover' : 'My Bloom',
          cycleLength: 28,
          periodLength: 5,
          lastPeriodStart: new Date().toISOString(),
          isPartner: mode === 'partner',
          isPregnancyMode: false,
          theme: 'rose',
          diaryPin: '1234'
        };

        users.push(newUser);
        localStorage.setItem('lumina_users', JSON.stringify(users));
        onLogin(newUser);
      }
    }, 1000);
  };

  return (
    <div className="min-h-screen bg-[#fffafb] flex items-center justify-center p-4 relative overflow-hidden">
      {/* Decorative Background Elements */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-pink-100 rounded-full blur-[100px] opacity-50"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-rose-100 rounded-full blur-[120px] opacity-50"></div>
      <div className="absolute top-1/4 right-10 w-20 h-20 text-pink-200 opacity-20 rotate-12 text-6xl">🌸</div>
      <div className="absolute bottom-1/4 left-10 w-20 h-20 text-rose-200 opacity-20 -rotate-12 text-6xl">✨</div>

      <div className="bg-white/70 backdrop-blur-2xl p-8 md:p-12 rounded-[3rem] shadow-[0_20px_50px_rgba(249,168,212,0.2)] w-full max-w-lg z-10 border border-white/50 flex flex-col items-center">
        <div className="mb-8 text-center">
          <h1 className="text-5xl font-serif text-pink-500 mb-2 italic tracking-tighter">Lumina</h1>
          <p className="text-pink-300 uppercase tracking-[0.3em] text-[10px] font-bold">Secure Sanctuary</p>
        </div>

        {/* Auth Mode Toggle */}
        <div className="flex bg-pink-50/50 p-1.5 rounded-2xl mb-8 w-full border border-pink-100/50">
          <button 
            onClick={() => { setIsLogin(true); setError(''); }}
            className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all duration-300 ${isLogin ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
          >
            SIGN IN
          </button>
          <button 
            onClick={() => { setIsLogin(false); setError(''); }}
            className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all duration-300 ${!isLogin ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
          >
            JOIN US
          </button>
        </div>

        {/* Identity Toggle (Only on Sign Up) */}
        {!isLogin && (
          <div className="flex bg-rose-50/30 p-1 rounded-full mb-8 w-full border border-rose-100/50">
            <button 
              onClick={() => setMode('user')}
              className={`flex-1 py-2 rounded-full text-[10px] font-bold transition-all ${mode === 'user' ? 'bg-pink-400 text-white shadow-md' : 'text-pink-300'}`}
            >
              I AM BLOOMING
            </button>
            <button 
              onClick={() => setMode('partner')}
              className={`flex-1 py-2 rounded-full text-[10px] font-bold transition-all ${mode === 'partner' ? 'bg-pink-400 text-white shadow-md' : 'text-pink-300'}`}
            >
              I AM SUPPORTING
            </button>
          </div>
        )}

        <form onSubmit={handleSubmit} className="w-full space-y-5">
          {error && (
            <div className="bg-rose-50 text-rose-500 text-[11px] font-bold p-4 rounded-2xl border border-rose-100 text-center animate-shake">
              {error}
            </div>
          )}

          {!isLogin && (
            <div className="group">
              <label className="block text-[10px] font-bold text-pink-300 uppercase mb-2 ml-4">Full Name</label>
              <div className="relative">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-pink-300">🎀</span>
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-12 pr-6 py-4 bg-white border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 placeholder:text-pink-200 transition-all shadow-sm"
                  placeholder="Your lovely name..."
                  required={!isLogin}
                />
              </div>
            </div>
          )}

          <div className="group">
            <label className="block text-[10px] font-bold text-pink-300 uppercase mb-2 ml-4">Email Address</label>
            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-pink-300">✉️</span>
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-12 pr-6 py-4 bg-white border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 placeholder:text-pink-200 transition-all shadow-sm"
                placeholder="hello@beautiful.com"
                required
              />
            </div>
          </div>

          <div className="group">
            <label className="block text-[10px] font-bold text-pink-300 uppercase mb-2 ml-4">Password</label>
            <div className="relative">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 text-pink-300">🔒</span>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-12 pr-6 py-4 bg-white border border-pink-50 rounded-2xl focus:ring-4 focus:ring-pink-100 outline-none text-pink-700 placeholder:text-pink-200 transition-all shadow-sm"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className="w-full py-5 bg-gradient-to-r from-pink-400 to-rose-400 hover:from-pink-500 hover:to-rose-500 text-white rounded-2xl font-bold shadow-xl shadow-pink-200 transition-all transform hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:translate-y-0 flex items-center justify-center gap-3"
          >
            {loading ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
            ) : (
              <>
                {isLogin ? 'WELCOME BACK' : 'START YOUR JOURNEY'}
                <span className="text-xl">✨</span>
              </>
            )}
          </button>
        </form>

        <div className="mt-10 flex flex-col items-center gap-4">
          <div className="flex items-center gap-2 text-[10px] text-pink-300 uppercase font-bold tracking-widest">
            <span className="w-10 h-[1px] bg-pink-100"></span>
            Privacy First
            <span className="w-10 h-[1px] bg-pink-100"></span>
          </div>
          <p className="text-[10px] text-gray-400 text-center max-w-[250px] leading-relaxed">
            Your data is locally protected and encrypted. We believe your cycle and thoughts are your sacred business.
          </p>
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-5px); }
          75% { transform: translateX(5px); }
        }
        .animate-shake {
          animation: shake 0.3s ease-in-out;
        }
      `}</style>
    </div>
  );
};

