import React, { useEffect, useState } from 'react';
import { User, Symptom, Reminder } from '../types';
import { getDailyAffirmation } from '../services/gemini';
import { SONGS } from '../constants';

interface DashboardProps {
  user: User;
  symptoms: Symptom[];
  waterIntake: number;
  setWaterIntake: React.Dispatch<React.SetStateAction<number>>;
  waterGoal: number;
  reminders: Reminder[];
  currentSongIndex: number;
  isMusicPlaying: boolean;
  toggleMusic: () => void;
  nextSong: () => void;
  prevSong: () => void;
  setCurrentSongIndex: (index: number) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  waterIntake, 
  setWaterIntake, 
  waterGoal, 
  reminders,
  currentSongIndex,
  isMusicPlaying,
  toggleMusic,
  nextSong,
  prevSong,
  setCurrentSongIndex
}) => {
  const [affirmation, setAffirmation] = useState("Loading your daily inspiration...");

  useEffect(() => {
    getDailyAffirmation().then(setAffirmation);
  }, []);

  const activeReminders = reminders.filter(r => !r.isCompleted);
  const currentSong = SONGS[currentSongIndex];

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Hero Welcome */}
      <section className="relative overflow-hidden bg-gradient-to-br from-pink-100 to-rose-50 p-8 rounded-[2rem] shadow-inner text-pink-600">
        <div className="relative z-10">
          <h2 className="text-4xl font-serif mb-2 italic">Welcome back, {user.name}</h2>
          <p className="text-sm opacity-80 mb-6 italic">Today is a beautiful day to bloom.</p>

          <div className="bg-white/40 backdrop-blur-sm p-4 rounded-2xl border border-white/40">
            <p className="text-xs font-bold uppercase tracking-widest text-pink-400 mb-1">Affirmation</p>
            <p className="text-lg font-serif italic text-pink-700 leading-relaxed">"{affirmation}"</p>
          </div>
        </div>
        <div className="absolute top-0 right-0 -translate-y-4 translate-x-4">
           <span className="text-9xl opacity-10">🌸</span>
        </div>
      </section>

      {/* Shared Partner Reminders */}
      {activeReminders.length > 0 && (
        <section className="bg-indigo-50/50 p-6 rounded-[2rem] border border-indigo-100">
          <h3 className="text-lg font-serif text-indigo-600 mb-4 flex items-center gap-2">
            <span className="text-xl">💌</span> From {user.partnerName}
          </h3>
          <div className="space-y-3">
            {activeReminders.map(reminder => (
              <div key={reminder.id} className="flex items-center gap-3 bg-white/80 p-4 rounded-2xl shadow-sm border border-indigo-50">
                <span className="text-lg">⏰</span>
                <div>
                  <p className="text-sm font-serif italic text-indigo-900 leading-tight">{reminder.text}</p>
                  <p className="text-[9px] text-indigo-400 font-bold uppercase">{reminder.time}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Aesthetic Music Player */}
      <section className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-pink-50 overflow-hidden relative">
        <div className="flex flex-col md:flex-row items-center gap-6">
          <div className="relative w-32 h-32 flex-shrink-0 group">
            <div className={`absolute inset-0 bg-gradient-to-br from-pink-200 to-rose-300 rounded-3xl shadow-lg transition-transform duration-700 ${isMusicPlaying ? 'rotate-3 scale-105' : ''}`}></div>
            <div className="absolute inset-0 flex items-center justify-center text-5xl">
              {isMusicPlaying ? '🌸' : '💤'}
            </div>
            {isMusicPlaying && (
              <div className="absolute -bottom-2 -right-2 flex gap-1">
                {[1, 2, 3].map(i => (
                  <div key={i} className={`w-1 bg-pink-400 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.15}s`, height: `${10 + i * 5}px` }}></div>
                ))}
              </div>
            )}
          </div>

          <div className="flex-1 text-center md:text-left">
            <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest mb-1">Now Playing</p>
            <h3 className="text-2xl font-serif text-pink-600 italic mb-1">{currentSong.title}</h3>
            <p className="text-sm text-pink-400 mb-6">{currentSong.artist}</p>

            <div className="flex items-center justify-center md:justify-start gap-6">
              <button onClick={prevSong} className="text-2xl text-pink-300 hover:text-pink-500 transition-colors">⏮</button>
              <button 
                onClick={toggleMusic}
                className="w-12 h-12 bg-pink-500 text-white rounded-full flex items-center justify-center shadow-lg shadow-pink-100 hover:scale-110 active:scale-95 transition-all"
              >
                {isMusicPlaying ? '⏸' : '▶'}
              </button>
              <button onClick={nextSong} className="text-2xl text-pink-300 hover:text-pink-500 transition-colors">⏭</button>
            </div>
          </div>
        </div>

        <div className="mt-8 space-y-2">
          <p className="text-[10px] font-bold text-pink-300 uppercase tracking-widest mb-3 ml-2">Playlist</p>
          <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
            {SONGS.map((song, i) => (
              <button 
                key={i}
                onClick={() => setCurrentSongIndex(i)}
                className={`flex-shrink-0 px-4 py-3 rounded-2xl border transition-all text-xs font-bold uppercase ${currentSongIndex === i ? 'bg-pink-100 border-pink-300 text-pink-600 shadow-sm' : 'bg-pink-50/30 border-transparent text-pink-300 hover:bg-pink-50'}`}
              >
                {song.title}
              </button>
            ))}
          </div>
        </div>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Cycle Phase */}
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-pink-50 flex flex-col justify-between">
          <div>
            <h3 className="text-xl font-serif text-pink-500 mb-4 flex items-center gap-2">
              <span className="text-2xl">🌙</span> Current Phase
            </h3>
            <div className="flex items-center gap-6">
              <div className="w-20 h-20 rounded-full border-4 border-pink-200 flex items-center justify-center relative">
                 <div className="w-16 h-16 rounded-full bg-pink-100 animate-pulse"></div>
                 <span className="absolute text-xs font-bold text-pink-400">Follicular</span>
              </div>
              <div>
                <p className="text-sm font-bold text-pink-600 uppercase">Day 8 of 28</p>
                <p className="text-xs text-pink-300">Predicting ovulation in 6 days</p>
              </div>
            </div>
          </div>
          <button className="mt-6 w-full py-3 bg-pink-50 text-pink-500 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-pink-100 transition-colors">
            Log Feeling
          </button>
        </div>

        {/* Water Intake */}
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-pink-50">
          <h3 className="text-xl font-serif text-pink-500 mb-4 flex items-center gap-2">
            <span className="text-2xl">💧</span> Hydration
          </h3>
          <div className="flex flex-col items-center gap-4">
            <div className="flex flex-wrap justify-center gap-2">
              {[...Array(waterGoal)].map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => setWaterIntake(Math.min(i + 1, waterGoal))}
                  className={`w-8 h-10 rounded-lg border-2 transition-all flex items-end justify-center overflow-hidden ${i < waterIntake ? 'bg-blue-100 border-blue-200' : 'bg-transparent border-gray-100'}`}
                >
                  {i < waterIntake && <div className="w-full bg-blue-400 animate-bounce h-1/2"></div>}
                </button>
              ))}
            </div>
            <p className="text-sm text-pink-400 font-bold uppercase tracking-widest">
              {waterIntake} of {waterGoal} glasses
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

