import React, { useState } from 'react';
import { Song, User } from '../types';
import { SONGS } from '../constants';

interface MusicRoomProps {
  user: User;
  onToggleFavorite: (songId: string) => void;
  currentSongIndex: number;
  onSelectSong: (index: number) => void;
  isMusicPlaying: boolean;
  onTogglePlay: () => void;
}

const MusicRoom: React.FC<MusicRoomProps> = ({ 
  user, 
  onToggleFavorite, 
  currentSongIndex, 
  onSelectSong, 
  isMusicPlaying,
  onTogglePlay
}) => {
  const [filter, setFilter] = useState<'all' | 'favorites'>('all');
  const [search, setSearch] = useState('');

  const favorites = user.favoriteSongs || [];

  const filteredSongs = SONGS.filter(song => {
    const matchesSearch = song.title.toLowerCase().includes(search.toLowerCase()) || 
                          song.artist.toLowerCase().includes(search.toLowerCase());
    const matchesFilter = filter === 'all' || favorites.includes(song.id);
    return matchesSearch && matchesFilter;
  });

  const currentSong = SONGS[currentSongIndex];

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <header className="text-center">
        <h2 className="text-3xl font-serif text-pink-500 italic">Music Sanctuary</h2>
        <p className="text-sm text-pink-300 italic">Your personal audio bouquet</p>
      </header>

      {/* Hero Player */}
      <section className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 relative overflow-hidden">
        <div className="flex flex-col items-center gap-6">
          <div className="relative w-48 h-48 group">
            <div className={`absolute inset-0 bg-gradient-to-br from-pink-200 to-rose-300 rounded-full shadow-2xl transition-all duration-1000 ${isMusicPlaying ? 'rotate-[360deg] animate-[spin_10s_linear_infinite]' : ''}`}>
               <div className="absolute inset-4 bg-white/20 backdrop-blur-md rounded-full border border-white/40 flex items-center justify-center text-6xl">
                 {currentSong.coverEmoji}
               </div>
            </div>
            {/* Center hole like a record */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-inner z-10"></div>
          </div>

          <div className="text-center space-y-2">
            <h3 className="text-2xl font-serif text-pink-600 italic">{currentSong.title}</h3>
            <p className="text-sm text-pink-400 font-bold uppercase tracking-widest">{currentSong.artist}</p>
          </div>

          <button 
            onClick={onTogglePlay}
            className="w-16 h-16 bg-pink-500 text-white rounded-full flex items-center justify-center shadow-xl shadow-pink-100 hover:scale-110 active:scale-95 transition-all text-2xl"
          >
            {isMusicPlaying ? '⏸' : '▶'}
          </button>
        </div>
      </section>

      {/* Library Controls */}
      <section className="space-y-6">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2">🔍</span>
            <input 
              type="text" 
              placeholder="Search library..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-12 pr-6 py-4 bg-white rounded-2xl border border-pink-50 outline-none focus:ring-2 focus:ring-pink-100 text-pink-600 italic"
            />
          </div>
          <div className="flex bg-pink-50/50 p-1.5 rounded-2xl border border-pink-100/50">
            <button 
              onClick={() => setFilter('all')}
              className={`px-6 py-2 rounded-xl text-[10px] font-bold transition-all ${filter === 'all' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
            >
              ALL TRACKS
            </button>
            <button 
              onClick={() => setFilter('favorites')}
              className={`px-6 py-2 rounded-xl text-[10px] font-bold transition-all ${filter === 'favorites' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
            >
              MY FAVORITES
            </button>
          </div>
        </div>

        <div className="grid gap-4">
          {filteredSongs.length === 0 ? (
            <div className="text-center py-12 bg-white rounded-[2.5rem] border border-dashed border-pink-200">
              <p className="text-pink-300 italic">No songs found in this mood...</p>
            </div>
          ) : (
            filteredSongs.map((song) => {
              const isCurrent = SONGS[currentSongIndex].id === song.id;
              const isFav = favorites.includes(song.id);
              return (
                <div 
                  key={song.id}
                  className={`group bg-white p-4 rounded-3xl border transition-all flex items-center justify-between cursor-pointer ${isCurrent ? 'border-pink-300 shadow-md shadow-pink-50' : 'border-pink-50 hover:border-pink-200'}`}
                  onClick={() => onSelectSong(SONGS.findIndex(s => s.id === song.id))}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl transition-all ${isCurrent ? 'bg-pink-100 scale-110' : 'bg-pink-50/50'}`}>
                      {song.coverEmoji}
                    </div>
                    <div>
                      <h4 className={`font-serif italic ${isCurrent ? 'text-pink-600' : 'text-gray-600'}`}>{song.title}</h4>
                      <p className="text-[9px] font-bold text-pink-300 uppercase tracking-tighter">{song.artist}</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-3">
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        onToggleFavorite(song.id);
                      }}
                      className={`text-2xl transition-transform hover:scale-125 ${isFav ? 'animate-pulse' : 'grayscale opacity-30 hover:grayscale-0 hover:opacity-100'}`}
                    >
                      {isFav ? '💖' : '🤍'}
                    </button>
                    {isCurrent && isMusicPlaying && (
                       <div className="flex gap-0.5 items-end h-4 w-4">
                          {[1,2,3].map(i => (
                            <div key={i} className="bg-pink-400 w-1 rounded-full animate-bounce" style={{ height: i*4, animationDelay: `${i*0.2}s` }}></div>
                          ))}
                       </div>
                    )}
                  </div>
                </div>
              );
            })
          )}
        </div>
      </section>
    </div>
  );
};

export default MusicRoom;

import React, { useState, useEffect, useRef } from 'react';
import { User, Symptom, DiaryEntry, SelfCareTask, AppTheme, Reminder, BirthControlLog } from './types';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import PeriodTracker from './components/PeriodTracker';
import SelfCare from './components/SelfCare';
import YogaTutorials from './components/YogaTutorials';
import Diary from './components/Diary';
import PartnerMode from './components/PartnerMode';
import WaterTracker from './components/WaterTracker';
import Education from './components/Education';
import PregnancyTracker from './components/PregnancyTracker';
import Settings from './components/Settings';
import MusicRoom from './components/MusicRoom';
import { playWelcomeVoice } from './services/gemini';
import { THEMES, SONGS } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [symptoms, setSymptoms] = useState<Symptom[]>([]);
  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
  const [waterIntake, setWaterIntake] = useState(0);
  const [waterGoal, setWaterGoal] = useState(8);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [currentSongIndex, setCurrentSongIndex] = useState(0);
  const [volume, setVolume] = useState(0.3);
  const [reminders, setReminders] = useState<Reminder[]>([]);
  const [bcLogs, setBcLogs] = useState<BirthControlLog[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [selfCareTasks, setSelfCareTasks] = useState<SelfCareTask[]>([
    { id: '1', task: 'Drink warm tea', completed: false },
    { id: '2', task: 'Read for 15 mins', completed: false },
    { id: '3', task: 'Skincare routine', completed: false },
  ]);

  const handleLogin = (userData: User) => {
    const fullUser: User = {
      ...userData,
      theme: userData.theme || 'rose',
      isPregnancyMode: userData.isPregnancyMode || false,
      diaryPin: userData.diaryPin || '1234',
      favoriteSongs: userData.favoriteSongs || [],
      birthControlConfig: userData.birthControlConfig || {
        method: 'Pill',
        frequency: 'daily',
        reminderTime: '09:00',
        enabled: false
      }
    };
    setUser(fullUser);
    playWelcomeVoice(fullUser.name);
    setIsMusicPlaying(true);
  };

  const updateTheme = (newTheme: AppTheme) => {
    if (user) {
      setUser({ ...user, theme: newTheme });
    }
  };

  const toggleFavoriteSong = (songId: string) => {
    if (!user) return;
    const currentFavs = user.favoriteSongs || [];
    const newFavs = currentFavs.includes(songId) 
      ? currentFavs.filter(id => id !== songId) 
      : [...currentFavs, songId];
    setUser({ ...user, favoriteSongs: newFavs });
  };

  const togglePregnancy = () => {
    if (user) {
      setUser({ 
        ...user, 
        isPregnancyMode: !user.isPregnancyMode,
        pregnancyStartDate: !user.isPregnancyMode ? new Date().toISOString() : undefined 
      });
    }
  };

  const updateBCConfig = (config: User['birthControlConfig']) => {
    if (user && config) {
      setUser({ ...user, birthControlConfig: config });
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab('dashboard');
    setIsMusicPlaying(false);
  };

  const toggleMusic = () => {
    setIsMusicPlaying(!isMusicPlaying);
  };

  const nextSong = () => {
    setCurrentSongIndex((prev) => (prev + 1) % SONGS.length);
  };

  const prevSong = () => {
    setCurrentSongIndex((prev) => (prev - 1 + SONGS.length) % SONGS.length);
  };

  useEffect(() => {
    if (audioRef.current) {
      if (isMusicPlaying) {
        audioRef.current.play().catch(e => console.log("Autoplay blocked", e));
      } else {
        audioRef.current.pause();
      }
    }
  }, [isMusicPlaying, currentSongIndex]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  const currentThemeData = THEMES[user.theme || 'rose'];
  const themeClass = `text-${currentThemeData.primary}`;

  const renderContent = () => {
    if (user.isPartner) {
      return <PartnerMode user={user} reminders={reminders} setReminders={setReminders} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <Dashboard 
            user={user} 
            symptoms={symptoms} 
            waterIntake={waterIntake} 
            setWaterIntake={setWaterIntake} 
            waterGoal={waterGoal} 
            reminders={reminders} 
            currentSongIndex={currentSongIndex}
            isMusicPlaying={isMusicPlaying}
            toggleMusic={toggleMusic}
            nextSong={nextSong}
            prevSong={prevSong}
            setCurrentSongIndex={setCurrentSongIndex}
          />
        );
      case 'cycle':
        return user.isPregnancyMode 
          ? <PregnancyTracker user={user} /> 
          : <PeriodTracker 
              user={user} 
              symptoms={symptoms} 
              setSymptoms={setSymptoms} 
              bcLogs={bcLogs} 
              setBcLogs={setBcLogs}
              onUpdateBCConfig={updateBCConfig}
            />;
      case 'edu':
        return <Education />;
      case 'music':
        return <MusicRoom 
          user={user} 
          onToggleFavorite={toggleFavoriteSong} 
          currentSongIndex={currentSongIndex} 
          onSelectSong={setCurrentSongIndex} 
          isMusicPlaying={isMusicPlaying} 
          onTogglePlay={toggleMusic} 
        />;
      case 'diary':
        return <Diary entries={diaryEntries} setEntries={setDiaryEntries} user={user} />;
      case 'selfcare':
        return <SelfCare tasks={selfCareTasks} setTasks={setSelfCareTasks} />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard user={user} symptoms={symptoms} waterIntake={waterIntake} setWaterIntake={setWaterIntake} waterGoal={waterGoal} reminders={reminders} />;
    }
  };

  return (
    <div className={`min-h-screen pb-24 ${currentThemeData.bg} selection:bg-pink-100 transition-colors duration-500`}>
      <audio 
        ref={audioRef}
        src={SONGS[currentSongIndex].url} 
        onEnded={nextSong}
        loop={false}
      />

      <header className="px-6 pt-10 pb-6 flex justify-between items-center bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-[60]">
        <div className="cursor-pointer" onClick={() => setActiveTab('dashboard')}>
          <h1 className={`text-3xl font-serif italic ${themeClass}`}>Lumina</h1>
          <div className="flex gap-1 mt-1">
            {(Object.keys(THEMES) as AppTheme[]).map(t => (
              <button 
                key={t}
                onClick={(e) => { e.stopPropagation(); updateTheme(t); }}
                className={`w-3 h-3 rounded-full border border-white shadow-sm ${t === 'rose' ? 'bg-pink-400' : t === 'lavender' ? 'bg-purple-400' : t === 'mint' ? 'bg-teal-400' : 'bg-orange-400'} ${user.theme === t ? 'ring-2 ring-offset-2 ring-gray-300' : ''}`}
              />
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          {!user.isPartner && (
            <button 
              onClick={togglePregnancy}
              className={`text-[10px] font-bold px-3 py-1 rounded-full border transition-all ${user.isPregnancyMode ? 'bg-indigo-500 text-white border-indigo-500' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              {user.isPregnancyMode ? 'PREGNANCY ON' : 'PREGNANCY OFF'}
            </button>
          )}

          <div className="flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-full border border-gray-100">
            <button onClick={toggleMusic} className="text-sm">
              {isMusicPlaying ? '⏸️' : '▶️'}
            </button>
            <input 
              type="range" min="0" max="1" step="0.01" value={volume} 
              onChange={(e) => setVolume(parseFloat(e.target.value))}
              className="w-12 h-1 accent-pink-400"
            />
          </div>

          <button onClick={() => setActiveTab('settings')} className="p-2 text-gray-400 hover:text-pink-400 transition-colors">
            ⚙️
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-6">
        {renderContent()}
      </main>

      {!user.isPartner && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-gray-100 flex justify-around items-center py-4 px-2 shadow-[0_-10px_30px_rgba(0,0,0,0.03)] z-50">
          <NavItem icon="🏠" label="Home" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} theme={user.theme} />
          <NavItem icon={user.isPregnancyMode ? "👶" : "🌸"} label={user.isPregnancyMode ? "Baby" : "Cycle"} active={activeTab === 'cycle'} onClick={() => setActiveTab('cycle')} theme={user.theme} />
          <NavItem icon="🎵" label="Music" active={activeTab === 'music'} onClick={() => setActiveTab('music')} theme={user.theme} />
          <NavItem icon="📔" label="Diary" active={activeTab === 'diary'} onClick={() => setActiveTab('diary')} theme={user.theme} />
          <NavItem icon="✨" label="Self" active={activeTab === 'selfcare'} onClick={() => setActiveTab('selfcare')} theme={user.theme} />
        </nav>
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void, theme: AppTheme }> = ({ icon, label, active, onClick, theme }) => {
  const color = THEMES[theme].primary;
  return (
    <button 
      onClick={onClick}
      className={`flex flex-col items-center gap-1 transition-all ${active ? `text-${color} scale-110 font-bold` : 'text-gray-400'}`}
    >
      <span className="text-xl">{icon}</span>
      <span className="text-[9px] uppercase tracking-tighter">{label}</span>
    </button>
  );
};

