import React, { useState } from 'react';
import { Song, User } from '../types';
import { SONGS } from '../constants';

interface MusicRoomProps {
  user: User;
  onToggleFavorite: (songId: string) => void;
  currentSongIndex: number;
  onSelectSong: (index: number) => void;
  isMusicPlaying: boolean;
  onTogglePlay: () => void;
  onAddCustomSong: (song: Song) => void;
}

const MusicRoom: React.FC<MusicRoomProps> = ({ 
  user, 
  onToggleFavorite, 
  currentSongIndex, 
  onSelectSong, 
  isMusicPlaying,
  onTogglePlay,
  onAddCustomSong
}) => {
  const [filter, setFilter] = useState<'all' | 'favorites' | 'custom'>('all');
  const [search, setSearch] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);

  // State for the "Add Song" form
  const [newTitle, setNewTitle] = useState('');
  const [newArtist, setNewArtist] = useState('');
  const [newUrl, setNewUrl] = useState('');
  const [newEmoji, setNewEmoji] = useState('🎵');

  const favorites = user.favoriteSongs || [];
  const customSongs = user.customSongs || [];
  const fullLibrary = [...SONGS, ...customSongs];

  const filteredSongs = fullLibrary.filter(song => {
    const matchesSearch = song.title.toLowerCase().includes(search.toLowerCase()) || 
                          song.artist.toLowerCase().includes(search.toLowerCase());
    const matchesFilter = 
      filter === 'all' || 
      (filter === 'favorites' && favorites.includes(song.id)) ||
      (filter === 'custom' && song.source !== 'internal');
    return matchesSearch && matchesFilter;
  });

  const currentSong = fullLibrary[currentSongIndex] || fullLibrary[0];

  const handleAddSong = () => {
    if (!newTitle || !newUrl) return;

    let source: Song['source'] = 'external';
    if (newUrl.includes('spotify')) source = 'spotify';
    else if (newUrl.includes('youtube') || newUrl.includes('youtu.be')) source = 'youtube';

    const newSong: Song = {
      id: 'custom-' + Math.random().toString(36).substr(2, 9),
      title: newTitle,
      artist: newArtist || 'Unknown Artist',
      url: newUrl,
      tags: ['custom'],
      coverEmoji: newEmoji,
      source
    };

    onAddCustomSong(newSong);
    setShowAddForm(false);
    setNewTitle('');
    setNewArtist('');
    setNewUrl('');
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <header className="text-center relative">
        <h2 className="text-3xl font-serif text-pink-500 italic">Music Sanctuary</h2>
        <p className="text-sm text-pink-300 italic">Your personal audio bouquet</p>
        <button 
          onClick={() => setShowAddForm(!showAddForm)}
          className="absolute right-0 top-0 w-10 h-10 bg-pink-100 text-pink-500 rounded-full flex items-center justify-center shadow-sm hover:scale-110 transition-transform"
        >
          {showAddForm ? '✕' : '+'}
        </button>
      </header>

      {showAddForm && (
        <section className="bg-white p-8 rounded-[2.5rem] shadow-lg border border-pink-100 animate-fadeIn space-y-4">
          <h3 className="text-xl font-serif text-pink-500 italic mb-4">Add Your Favorite Track</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              type="text" placeholder="Song Title (e.g. Flowers)" 
              value={newTitle} onChange={(e) => setNewTitle(e.target.value)}
              className="w-full p-4 bg-pink-50/50 rounded-2xl outline-none focus:ring-2 focus:ring-pink-200 text-pink-700 italic border border-pink-50"
            />
            <input 
              type="text" placeholder="Artist (e.g. Miley Cyrus)" 
              value={newArtist} onChange={(e) => setNewArtist(e.target.value)}
              className="w-full p-4 bg-pink-50/50 rounded-2xl outline-none focus:ring-2 focus:ring-pink-200 text-pink-700 italic border border-pink-50"
            />
          </div>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-pink-300">🔗</span>
            <input 
              type="text" placeholder="Spotify or YouTube Link" 
              value={newUrl} onChange={(e) => setNewUrl(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-pink-50/50 rounded-2xl outline-none focus:ring-2 focus:ring-pink-200 text-pink-700 italic border border-pink-50"
            />
          </div>
          <div className="flex gap-4 items-center">
            <label className="text-xs font-bold text-pink-300 uppercase">Pick Emoji</label>
            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
              {['🎵', '🎧', '🎸', '🎹', '💖', '👑', '🌈', '🦋'].map(e => (
                <button 
                  key={e} onClick={() => setNewEmoji(e)}
                  className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl transition-all ${newEmoji === e ? 'bg-pink-400 scale-110 shadow-md' : 'bg-pink-50'}`}
                >
                  {e}
                </button>
              ))}
            </div>
          </div>
          <button 
            onClick={handleAddSong}
            className="w-full py-4 bg-pink-400 text-white rounded-2xl font-bold uppercase tracking-widest shadow-lg shadow-pink-100 hover:bg-pink-500 transition-all"
          >
            Add to Library
          </button>
        </section>
      )}

      {/* Hero Player */}
      <section className="bg-white p-8 rounded-[3rem] shadow-sm border border-pink-50 relative overflow-hidden">
        <div className="flex flex-col items-center gap-6">
          <div className="relative w-48 h-48 group">
            <div className={`absolute inset-0 bg-gradient-to-br from-pink-200 to-rose-300 rounded-full shadow-2xl transition-all duration-1000 ${isMusicPlaying ? 'rotate-[360deg] animate-[spin_10s_linear_infinite]' : ''}`}>
               <div className="absolute inset-4 bg-white/20 backdrop-blur-md rounded-full border border-white/40 flex items-center justify-center text-6xl">
                 {currentSong.coverEmoji}
               </div>
            </div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-inner z-10"></div>
          </div>

          <div className="text-center space-y-2">
            <div className="flex items-center justify-center gap-2">
              {currentSong.source !== 'internal' && (
                <span className="text-[10px] bg-pink-100 text-pink-500 px-2 py-0.5 rounded-full font-bold uppercase">
                  {currentSong.source}
                </span>
              )}
              <h3 className="text-2xl font-serif text-pink-600 italic">{currentSong.title}</h3>
            </div>
            <p className="text-sm text-pink-400 font-bold uppercase tracking-widest">{currentSong.artist}</p>
          </div>

          <div className="flex items-center gap-6">
             <button 
               onClick={() => {
                 if (currentSong.source !== 'internal') {
                   window.open(currentSong.url, '_blank');
                 } else {
                   onTogglePlay();
                 }
               }}
               className="w-16 h-16 bg-pink-500 text-white rounded-full flex items-center justify-center shadow-xl shadow-pink-100 hover:scale-110 active:scale-95 transition-all text-2xl"
             >
               {currentSong.source !== 'internal' ? '↗' : (isMusicPlaying ? '⏸' : '▶')}
             </button>
          </div>
          {currentSong.source !== 'internal' && (
            <p className="text-[10px] text-pink-300 italic">Tap to open in {currentSong.source} app</p>
          )}
        </div>
      </section>

      {/* Library Controls */}
      <section className="space-y-6">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2">🔍</span>
            <input 
              type="text" 
              placeholder="Search your tracks..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-12 pr-6 py-4 bg-white rounded-2xl border border-pink-50 outline-none focus:ring-2 focus:ring-pink-100 text-pink-600 italic"
            />
          </div>
          <div className="flex bg-pink-50/50 p-1.5 rounded-2xl border border-pink-100/50">
            <button 
              onClick={() => setFilter('all')}
              className={`px-4 py-2 rounded-xl text-[9px] font-bold transition-all ${filter === 'all' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
            >
              ALL
            </button>
            <button 
              onClick={() => setFilter('favorites')}
              className={`px-4 py-2 rounded-xl text-[9px] font-bold transition-all ${filter === 'favorites' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
            >
              FAVES
            </button>
            <button 
              onClick={() => setFilter('custom')}
              className={`px-4 py-2 rounded-xl text-[9px] font-bold transition-all ${filter === 'custom' ? 'bg-white text-pink-500 shadow-sm' : 'text-pink-300'}`}
            >
              MY LINKS
            </button>
          </div>
        </div>

        <div className="grid gap-4">
          {filteredSongs.length === 0 ? (
            <div className="text-center py-12 bg-white rounded-[2.5rem] border border-dashed border-pink-200">
              <p className="text-pink-300 italic">No tracks in this playlist yet...</p>
            </div>
          ) : (
            filteredSongs.map((song) => {
              const songIdx = fullLibrary.findIndex(s => s.id === song.id);
              const isCurrent = currentSongIndex === songIdx;
              const isFav = favorites.includes(song.id);

              return (
                <div 
                  key={song.id}
                  className={`group bg-white p-4 rounded-3xl border transition-all flex items-center justify-between cursor-pointer ${isCurrent ? 'border-pink-300 shadow-md shadow-pink-50' : 'border-pink-50 hover:border-pink-200'}`}
                  onClick={() => onSelectSong(songIdx)}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl transition-all ${isCurrent ? 'bg-pink-100 scale-110' : 'bg-pink-50/50'}`}>
                      {song.coverEmoji}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <h4 className={`font-serif italic ${isCurrent ? 'text-pink-600 font-bold' : 'text-gray-600'}`}>{song.title}</h4>
                        {song.source !== 'internal' && (
                           <span className="text-[8px] bg-pink-50 text-pink-400 px-1.5 rounded-full font-bold uppercase">{song.source}</span>
                        )}
                      </div>
                      <p className="text-[9px] font-bold text-pink-300 uppercase tracking-tighter">{song.artist}</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-3">
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        onToggleFavorite(song.id);
                      }}
                      className={`text-xl transition-transform hover:scale-125 ${isFav ? 'animate-pulse grayscale-0' : 'grayscale opacity-30 hover:grayscale-0 hover:opacity-100'}`}
                    >
                      {isFav ? '💖' : '🤍'}
                    </button>
                    {isCurrent && isMusicPlaying && song.source === 'internal' && (
                       <div className="flex gap-0.5 items-end h-4 w-4">
                          {[1,2,3].map(i => (
                            <div key={i} className="bg-pink-400 w-1 rounded-full animate-bounce" style={{ height: i*4, animationDelay: `${i*0.2}s` }}></div>
                          ))}
                       </div>
                    )}
                  </div>
                </div>
              );
            })
          )}
        </div>
      </section>
    </div>
  );
};

export default MusicRoom;

